INSERT INTO OrleansQuery(QueryKey, QueryText) VALUES ( 'UpdateIAmAlivetimeKey',' SELECT * from update_i_am_alive_time( @DeploymentId, @Address, @Port, @Generation, @IAmAliveTime ); ');
INSERT INTO OrleansQuery(QueryKey, QueryText) VALUES ( 'InsertMembershipVersionKey',' SELECT * FROM insert_membership_version( @DeploymentId ); ');
INSERT INTO OrleansQuery(QueryKey, QueryText) VALUES ( 'InsertMembershipKey',' SELECT * FROM insert_membership( @DeploymentId, @Address, @Port, @Generation, @SiloName, @HostName, @Status, @ProxyPort, @StartTime, @IAmAliveTime, @Version ); ');
INSERT INTO OrleansQuery(QueryKey, QueryText) VALUES ( 'UpdateMembershipKey',' SELECT * FROM update_membership( @DeploymentId, @Address, @Port, @Generation, @Status, @SuspectTimes, @IAmAliveTime, @Version ); ');
INSERT INTO OrleansQuery(QueryKey, QueryText) VALUES ( 'MembershipReadRowKey',' SELECT v.DeploymentId, m.Address, m.Port, m.Generation, m.SiloName, m.HostName, m.Status, m.ProxyPort, m.SuspectTimes, m.StartTime, m.IAmAliveTime, v.Version FROM OrleansMembershipVersionTable v LEFT OUTER JOIN OrleansMembershipTable m ON v.DeploymentId = m.DeploymentId AND Address = @Address AND @Address IS NOT NULL AND Port = @Port AND @Port IS NOT NULL AND Generation = @Generation AND @Generation IS NOT NULL WHERE v.DeploymentId = @DeploymentId AND @DeploymentId IS NOT NULL; ');
INSERT INTO OrleansQuery(QueryKey, QueryText) VALUES ( 'MembershipReadAllKey',' SELECT v.DeploymentId, m.Address, m.Port, m.Generation, m.SiloName, m.HostName, m.Status, m.ProxyPort, m.SuspectTimes, m.StartTime, m.IAmAliveTime, v.Version FROM OrleansMembershipVersionTable v LEFT OUTER JOIN OrleansMembershipTable m ON v.DeploymentId = m.DeploymentId WHERE v.DeploymentId = @DeploymentId AND @DeploymentId IS NOT NULL; ');
INSERT INTO OrleansQuery(QueryKey, QueryText) VALUES ( 'DeleteMembershipTableEntriesKey',' DELETE FROM OrleansMembershipTable WHERE DeploymentId = @DeploymentId AND @DeploymentId IS NOT NULL; DELETE FROM OrleansMembershipVersionTable WHERE DeploymentId = @DeploymentId AND @DeploymentId IS NOT NULL; ');
INSERT INTO OrleansQuery(QueryKey, QueryText) VALUES ( 'GatewaysQueryKey',' SELECT Address, ProxyPort, Generation FROM OrleansMembershipTable WHERE DeploymentId = @DeploymentId AND @DeploymentId IS NOT NULL AND Status = @Status AND @Status IS NOT NULL AND ProxyPort > 0; ');
INSERT INTO OrleansQuery(QueryKey, QueryText) VALUES ( 'CleanupDefunctSiloEntriesKey',' DELETE FROM OrleansMembershipTable WHERE DeploymentId = @DeploymentId AND @DeploymentId IS NOT NULL AND IAmAliveTime < @IAmAliveTime AND Status != 3; ');
INSERT INTO OrleansQuery(QueryKey, QueryText) VALUES ( 'WriteToStorageKey',' select * from WriteToStorage(@GrainIdHash, @GrainIdN0, @GrainIdN1, @GrainTypeHash, @GrainTypeString, @GrainIdExtensionString, @ServiceId, @GrainStateVersion, @PayloadBinary); ');
INSERT INTO OrleansQuery(QueryKey, QueryText) VALUES ( 'ReadFromStorageKey',' SELECT PayloadBinary, (now() at time zone ''utc''), Version FROM OrleansStorage WHERE GrainIdHash = @GrainIdHash AND GrainTypeHash = @GrainTypeHash AND @GrainTypeHash IS NOT NULL AND GrainIdN0 = @GrainIdN0 AND @GrainIdN0 IS NOT NULL AND GrainIdN1 = @GrainIdN1 AND @GrainIdN1 IS NOT NULL AND GrainTypeString = @GrainTypeString AND GrainTypeString IS NOT NULL AND ((@GrainIdExtensionString IS NOT NULL AND GrainIdExtensionString IS NOT NULL AND GrainIdExtensionString = @GrainIdExtensionString) OR @GrainIdExtensionString IS NULL AND GrainIdExtensionString IS NULL) AND ServiceId = @ServiceId AND @ServiceId IS NOT NULL ');
INSERT INTO OrleansQuery(QueryKey, QueryText) VALUES ( 'ClearStorageKey',' UPDATE OrleansStorage SET PayloadBinary = NULL, Version = Version + 1 WHERE GrainIdHash = @GrainIdHash AND @GrainIdHash IS NOT NULL AND GrainTypeHash = @GrainTypeHash AND @GrainTypeHash IS NOT NULL AND GrainIdN0 = @GrainIdN0 AND @GrainIdN0 IS NOT NULL AND GrainIdN1 = @GrainIdN1 AND @GrainIdN1 IS NOT NULL AND GrainTypeString = @GrainTypeString AND @GrainTypeString IS NOT NULL AND ((@GrainIdExtensionString IS NOT NULL AND GrainIdExtensionString IS NOT NULL AND GrainIdExtensionString = @GrainIdExtensionString) OR @GrainIdExtensionString IS NULL AND GrainIdExtensionString IS NULL) AND ServiceId = @ServiceId AND @ServiceId IS NOT NULL AND Version IS NOT NULL AND Version = @GrainStateVersion AND @GrainStateVersion IS NOT NULL Returning Version as NewGrainStateVersion ');
INSERT INTO OrleansQuery(QueryKey, QueryText) VALUES ( 'DeleteStorageKey',' DELETE FROM OrleansStorage WHERE GrainIdHash = @GrainIdHash AND @GrainIdHash IS NOT NULL AND GrainTypeHash = @GrainTypeHash AND @GrainTypeHash IS NOT NULL AND GrainIdN0 = @GrainIdN0 AND @GrainIdN0 IS NOT NULL AND GrainIdN1 = @GrainIdN1 AND @GrainIdN1 IS NOT NULL AND GrainTypeString = @GrainTypeString AND @GrainTypeString IS NOT NULL AND ((@GrainIdExtensionString IS NOT NULL AND GrainIdExtensionString IS NOT NULL AND GrainIdExtensionString = @GrainIdExtensionString) OR @GrainIdExtensionString IS NULL AND GrainIdExtensionString IS NULL) AND ServiceId = @ServiceId AND @ServiceId IS NOT NULL AND Version IS NOT NULL AND Version = @GrainStateVersion AND @GrainStateVersion IS NOT NULL Returning Version + 1 as NewGrainStateVersion ');
